# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
import json

def lambda_handler(event, context):
    # Retrieve connection details from environment variables or secure parameters
    host = 'your_rds_host'
    user = 'your_rds_user'
    password = 'your_rds_password'
    db = 'your_database_name'

    # Extract search parameters from the API Gateway event
    search_params = event.get('queryStringParameters', {})

    # Initialize SQL query components
    sql_query = "SELECT * FROM products WHERE 1=1"
    params = []

    # Dynamically build SQL query based on search parameters
    if 'name' in search_params:
        sql_query += " AND name LIKE %s"
        params.append(f"%{search_params['name']}%")
    
    if 'category' in search_params:
        sql_query += " AND category = %s"
        params.append(search_params['category'])
    
    if 'price_min' in search_params and search_params['price_min'].isdigit():
        sql_query += " AND price >= %s"
        params.append(int(search_params['price_min']))
    
    if 'price_max' in search_params and search_params['price_max'].isdigit():
        sql_query += " AND price <= %s"
        params.append(int(search_params['price_max']))

    try:
        # Connect to the RDS MySQL database
        connection = pymysql.connect(host=host, user=user, password=password, db=db)
        
        # Execute the dynamic SQL query
        with connection.cursor() as cursor:
            cursor.execute(sql_query, params)
            result = cursor.fetchall()
        
        # Convert the result to JSON format
        response_body = json.dumps(result, default=str)
        
    except pymysql.MySQLError as e:
        return {
            'statusCode': 500,
            'body': f"Database error: {e}"
        }
    
    finally:
        # Close the database connection
        if connection:
            connection.close()
    
    # Return the response with the search results
    return {
        'statusCode': 200,
        'headers': {
            'Content-Type': 'application/json'
        },
        'body': response_body
    }